out_path = "ebay/data/dows/output/author_batches/out_05.jsonl"
with open(out_path, "a") as f:
    for it in items:
        assert len(it["mobile"]) <= 700, (it["item_id"], len(it["mobile"]))
        if it["title_issue"]:
            assert 0 < len(it["new_title"]) <= 80, (it["item_id"], len(it["new_title"]))
        else:
            assert it["new_title"] == ""
        f.write(json.dumps(it) + "\n")
print("wrote", len(items))
